<?php
namespace App\Domain\Shops;
use InvalidArgumentException;
final class ShopPurchaseRate{public function toBasisPoints($percentage){if(!is_string($percentage)&&!is_int($percentage))throw new InvalidArgumentException('Shop purchase percentage must be a decimal string.');$value=trim((string)$percentage);if(!preg_match('/^(0|[1-9][0-9]?|100)(?:\.([0-9]{1,2}))?$/D',$value,$matches))throw new InvalidArgumentException('Shop purchase percentage must have at most two decimals.');$whole=(int)$matches[1];$fraction=isset($matches[2])?str_pad($matches[2],2,'0'):0;if($whole===100&&(int)$fraction!==0)throw new InvalidArgumentException('Shop purchase percentage cannot exceed 100.');$basisPoints=$whole*100+(int)$fraction;if($basisPoints<1||$basisPoints>10000)throw new InvalidArgumentException('Shop purchase percentage must be between 0.01 and 100.');return$basisPoints;}public function toPercentage($basisPoints){if(!is_int($basisPoints)||$basisPoints<1||$basisPoints>10000)throw new InvalidArgumentException('Invalid Shop purchase rate basis points.');$whole=intdiv($basisPoints,100);$fraction=$basisPoints%100;if($fraction===0)return(string)$whole;if($fraction%10===0)return$whole.'.'.intdiv($fraction,10);return$whole.'.'.str_pad((string)$fraction,2,'0',STR_PAD_LEFT);}}
